create table if not exists public.incident_status_cache (
	id bigint primary key generated always as identity,
	incident_id text unique not null,
	shortlink text unique not null,
	updated_at timestamptz not null default now(),
	affects_project_creation boolean not null default false,
	affected_regions text[]
);

alter table public.incident_status_cache
enable row level security;

revoke all on public.incident_status_cache from anon;
revoke all on public.incident_status_cache from authenticated;

create index if not exists idx_incident_status_cache_incident_id
on public.incident_status_cache (incident_id);

create index if not exists idx_incident_status_cache_shortlink
on public.incident_status_cache (shortlink);

create or replace function public.set_updated_at()
returns trigger
language plpgsql
as $$
begin
	new.updated_at = now();
	return new;
end;
$$;

create trigger set_incident_status_cache_updated_at
before update on public.incident_status_cache
for each row
execute function public.set_updated_at();

--
-- Test built-in conversion functions.
--

-- Helper function to test a conversion. Uses the test_enc_conversion function
-- that was created in the create_function_0 test.
create or replace function test_conv(
  input IN bytea,
  src_encoding IN text,
  dst_encoding IN text,

  result OUT bytea,
  errorat OUT bytea,
  error OUT text)
language plpgsql as
$$
declare
  validlen int;
begin
  -- First try to perform the conversion with noError = false. If that errors out,
  -- capture the error message, and try again with noError = true. The second call
  -- should succeed and return the position of the error, return that too.
  begin
    select * into validlen, result from test_enc_conversion(input, src_encoding, dst_encoding, false);
    errorat = NULL;
    error := NULL;
  exception when others then
    error := sqlerrm;
    select * into validlen, result from test_enc_conversion(input, src_encoding, dst_encoding, true);
    errorat = substr(input, validlen + 1);
  end;
  return;
end;
$$

create or replace function public.publish_package_version(
    package_name app.valid_name,
    version_source text,
    version_description text,
    version text
)
    returns uuid
    language plpgsql
as $$
declare
    account app.accounts = account from app.accounts account where id = auth.uid();
    package_id uuid;
    version_id uuid;
begin
    if account.handle is null then
        raise exception 'user not logged in';
    end if;

    select ap.id
    from app.packages ap
    where ap.handle = account.handle and ap.partial_name = publish_package_version.package_name
    into package_id;

    begin
        insert into app.package_versions(package_id, version_struct, sql, description_md)
        values (package_id, app.text_to_semver(version), version_source, version_description)
        returning id into version_id;

        return version_id;
    exception when unique_violation then
        return null;
    end;
end;
$$

create or replace function public.publish_package_upgrade(
    package_name app.valid_name,
    upgrade_source text,
    from_version text,
    to_version text
)
    returns uuid
    language plpgsql
as $$
declare
    account app.accounts = account from app.accounts account where id = auth.uid();
    package_id uuid;
    upgrade_id uuid;
begin
    if account.handle is null then
        raise exception 'user not logged in';
    end if;

    select ap.id
    from app.packages ap
    where ap.handle = account.handle and ap.partial_name = publish_package_upgrade.package_name
    into package_id;

    begin
        insert into app.package_upgrades(package_id, from_version_struct, to_version_struct, sql)
        values (package_id, app.text_to_semver(from_version), app.text_to_semver(to_version), upgrade_source)
        returning id into upgrade_id;

        return upgrade_id;
    exception when unique_violation then
        return null;
    end;
end;
$$

create or replace function public.publish_package(
    package_name app.valid_name,
    package_description varchar(1000),
    relocatable bool default false,
    requires text[] default '{}'
)
    returns void
    language plpgsql
as $$
declare
    account app.accounts = account from app.accounts account where id = auth.uid();
    require text;
begin
    if account.handle is null then
        raise exception 'user not logged in';
    end if;

    foreach require in array requires
    loop
        if not exists (
            select true
            from app.allowed_extensions
            where
                name = require
        ) then
            raise exception '`requires` in the control file can''t have `%` in it', require;
        end if;
    end loop;

    insert into app.packages(handle, partial_name, control_description, control_relocatable, control_requires)
    values (account.handle, package_name, package_description, relocatable, requires)
    on conflict on constraint packages_handle_partial_name_key
    do update
    set control_description = excluded.control_description,
        control_relocatable = excluded.control_relocatable,
        control_requires = excluded.control_requires;
end;
$$

create or replace function audit.enable_tracking(regclass)
    returns void
    volatile
    security definer
    set search_path = ''
    language plpgsql
as $$
declare
    statement_row text = format('
        create trigger audit_i_u_d
            after insert or update or delete
            on %s
            for each row
            execute procedure audit.insert_update_delete_trigger();',
        $1
    );

    statement_stmt text = format('
        create trigger audit_t
            after truncate
            on %s
            for each statement
            execute procedure audit.truncate_trigger();',
        $1
    );

    pkey_cols text[] = audit.primary_key_columns($1);
begin
    if pkey_cols = array[]::text[] then
        raise exception 'Table % can not be audited because it has no primary key', $1;
    end if;

    if not exists(select 1 from pg_trigger where tgrelid = $1 and tgname = 'audit_i_u_d') then
        execute statement_row;
    end if;

    if not exists(select 1 from pg_trigger where tgrelid = $1 and tgname = 'audit_t') then
        execute statement_stmt;
    end if;
end;
$$

create function execute(stmt text, parameters jsonb default NULL,
                        types regtype[] default NULL::regtype[])
    returns table
            (
                stmt_row jsonb
            )
as
$pgsql$
declare
    rec            record;
    retrec         record;
begin
    for rec in select source                                              as stmt,
                      coalesce(not lead(true) over (), true)              as last
               from omni_sql.raw_statements(stmt::cstring)
        loop
            if not rec.last then
                execute rec.stmt;
            else
                for retrec in select omni_sql.execute_parameterized(rec.stmt, parameters, types) val
                    loop
                        stmt_row := to_jsonb(retrec.val);
                        return next;
                    end loop;
            end if;
        end loop;
    return;
end;
$pgsql$
    language plpgsql

